mapper.update:
UPDATE sm_subscription
SET plan = #{plan}, billing_cycle = #{billingCycle},
    status = #{status}, next_billing_at = #{nextBillingAt}
WHERE member_id = #{memberId}

UPDATE sm_subscription
SET next_billing_at = #{nextBillingAt}
WHERE member_id = #{memberId}

UPDATE sm_payment
SET status = #{status}, raw_response = #{raw}
WHERE order_id = #{orderId}

mapper.select:
SELECT id, order_name, amount, status, method,
       card_number_last4 AS card_last4, approved_at, receipt_url
FROM sm_payment
WHERE member_id = #{memberId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, member_id, order_id, amount, status
FROM sm_payment
WHERE order_id = #{orderId}

SELECT shorts_count, longform_count, voice_clone_count, ai_rewrite_count
FROM sm_usage
WHERE member_id = #{memberId} AND `year_month` = #{yearMonth}
